 467→  RETURNED_TO_SENDER: 3,
 468→  DELETED: 4,
 469→  MADE_PERMANENT: 5,
 470→} as const;
 471→
 472→export const MailResult = {
 473→  OK: 0,
 474→  ERR_EQUIP_ERROR: 1,
 475→  ERR_CANNOT_SEND_TO_SELF: 2,
 476→  ERR_NOT_ENOUGH_MONEY: 3,
 477→  ERR_RECIPIENT_NOT_FOUND: 4,
 478→  ERR_NOT_YOUR_TEAM: 5,
 479→  ERR_INTERNAL_ERROR: 6,
 480→  ERR_DISABLED_FOR_TRIAL_ACC: 14,
 481→  ERR_RECIPIENT_CAP_REACHED: 15,
 482→  ERR_CANT_SEND_WRAPPED_COD: 16,
 483→  ERR_MAIL_AND_CHAT_SUSPENDED: 17,
