 489→export type MailEntry = {
 490→  messageId: number;
 491→  messageType: number;
 492→  senderGuid?: bigint;
 493→  senderEntry?: number;
 494→  cod: number;
 495→  stationery: number;
 496→  money: number;
 497→  flags: number;
 498→  expirationDays: number;
 499→  subject: string;
 500→  body: string;
 501→  itemCount: number;
 502→};
 503→
 504→export type MailListResult = {
 505→  totalCount: number;
 506→  entries: MailEntry[];
 507→};
 508→
 509→export type SendMailResultPacket = {
 510→  mailId: number;
 511→  action: number;
 512→  result: number;
 513→};
