 515→export function parseShowMailbox(r: PacketReader): bigint {
 516→  return r.uint64LE();
 517→}
 518→
 519→export function parseMailListResult(r: PacketReader): MailListResult {
 520→  const totalCount = r.uint32LE();
 521→  const count = r.uint8();
 522→  const entries: MailEntry[] = [];
 523→  for (let i = 0; i < count; i++) {
 524→    const size = r.uint16LE();
 525→    const entryStart = r.offset;
 526→    const messageId = r.uint32LE();
 527→    const messageType = r.uint8();
 528→    let senderGuid: bigint | undefined;
 529→    let senderEntry: number | undefined;
 530→    if (messageType === MailMessageType.NORMAL) {
 531→      senderGuid = r.uint64LE();
 532→    } else {
 533→      senderEntry = r.uint32LE();
 534→    }
 535→    const cod = r.uint32LE();
 536→    r.uint32LE();
 537→    const stationery = r.uint32LE();
 538→    const money = r.uint32LE();
 539→    const flags = r.uint32LE();
 540→    const expirationDays = r.floatLE();
 541→    r.uint32LE();
 542→    const subject = r.cString();
 543→    const body = r.cString();
 544→    const itemCount = r.uint8();
 545→    const consumed = r.offset - entryStart;
 546→    if (consumed < size) r.skip(size - consumed);
 547→    entries.push({
 548→      messageId,
 549→      messageType,
 550→      senderGuid,
 551→      senderEntry,
 552→      cod,
 553→      stationery,
 554→      money,
 555→      flags,
 556→      expirationDays,
 557→      subject,
 558→      body,
 559→      itemCount,
 560→    });
 561→  }
 562→  return { totalCount, entries };
 563→}
