): string {
  if (entries.length === 0) return "[mail] Mailbox is empty";
  const lines: string[] = [`=== Mailbox (${entries.length} messages) ===`];
  for (let i = 0; i < entries.length; i++) {
    const e = entries[i]!;
    const unread = !(e.flags & MailCheckMask.READ);
    const marker = unread ? "*" : " ";
    const idx = `#${i + 1}`;
