): string {
  const age = formatMailAge(entry.expirationDays);
  const lines = [`From: ${sender}`, `Subject: ${entry.subject}`, `Date: ${age} ago`];
  if (entry.money > 0) {
    const gold = Math.floor(entry.money / 10000);
