280→function drainWorldPackets(conn: WorldConn): void {
281→  while (true) {
282→    if (!conn.pendingHeader) {
283→      if (conn.buf.length < INCOMING_HEADER_SIZE) break;
284→      conn.pendingHeader = decryptIncomingHeader(
285→        conn.buf.drain(INCOMING_HEADER_SIZE),
286→        conn.arc4,
287→      );
288→    }
289→    const bodySize = conn.pendingHeader.size - 2;
290→    if (conn.buf.length < bodySize) break;
291→
292→    const { opcode } = conn.pendingHeader;
293→    conn.pendingHeader = undefined;
294→    try {
295→      conn.dispatch.handle(opcode, new PacketReader(conn.buf.drain(bodySize)));
296→    } catch (err) {
297→      if (err instanceof Error) {
298→        conn.onPacketError?.(opcode, err);
299→      }
300→    }
301→  }
302→}
