304→async function authenticateWorld(
305→  conn: WorldConn,
306→  config: ClientConfig,
307→  auth: AuthResult,
308→): Promise<void> {
309→  const challenge = await conn.dispatch.expect(GameOpcode.SMSG_AUTH_CHALLENGE);
310→  challenge.uint32LE();
311→  const serverSeed = challenge.bytes(4);
312→
313→  const body = await buildWorldAuthPacket(
314→    config.account,
315→    auth.sessionKey,
316→    serverSeed,
317→    auth.realmId,
318→    config.clientSeed,
319→  );
320→  conn.socket.write(buildOutgoingPacket(GameOpcode.CMSG_AUTH_SESSION, body));
321→  conn.arc4 = new Arc4(auth.sessionKey);
322→
323→  const resp = await conn.dispatch.expect(GameOpcode.SMSG_AUTH_RESPONSE);
324→  const status = resp.uint8();
325→  if (status !== 0x0c) {
326→    const names: Record<number, string> = {
327→      0x0d: "system error",
328→      0x15: "account in use",
329→    };
330→    const label = names[status] ?? `status 0x${status.toString(16)}`;
331→    throw new Error(`World auth failed: ${label}`);
332→  }
333→}
