335→async function selectCharacter(
336→  conn: WorldConn,
337→  config: ClientConfig,
338→): Promise<void> {
339→  sendPacket(conn, GameOpcode.CMSG_CHAR_ENUM);
340→
341→  const enumReader = await conn.dispatch.expect(GameOpcode.SMSG_CHAR_ENUM);
342→  const chars = parseCharacterList(enumReader);
343→  const char = chars.find(
344→    (c) => c.name.toLowerCase() === config.character.toLowerCase(),
345→  );
346→  if (!char) {
347→    throw new Error(
348→      `Character "${config.character}" not found. Available: ${chars.map((c) => c.name).join(", ")}`,
349→    );
350→  }
351→
352→  conn.selfName = char.name;
353→  conn.selfGuidLow = char.guidLow;
354→  conn.selfGuidHigh = char.guidHigh;
355→  conn.guildId = char.guildId;
356→
357→  const w = new PacketWriter();
358→  w.uint32LE(char.guidLow);
359→  w.uint32LE(char.guidHigh);
360→  sendPacket(conn, GameOpcode.CMSG_PLAYER_LOGIN, w.finish());
361→
362→  await conn.dispatch.expect(GameOpcode.SMSG_LOGIN_VERIFY_WORLD);
363→}
