365→function startPingLoop(
366→  conn: WorldConn,
367→  intervalMs: number,
368→): ReturnType<typeof setInterval> {
369→  return setInterval(() => {
370→    const w = new PacketWriter();
371→    w.uint32LE(0);
372→    w.uint32LE(0);
373→    sendPacket(conn, GameOpcode.CMSG_PING, w.finish());
374→  }, intervalMs);
375→}
