661→          switch (mode.type) {
662→            case "say":
663→              handle.sendSay(message);
664→              break;
665→            case "yell":
666→              handle.sendYell(message);
667→              break;
668→            case "guild":
669→              handle.sendGuild(message);
670→              break;
671→            case "party":
672→              handle.sendParty(message);
673→              break;
674→            case "raid":
675→              handle.sendRaid(message);
676→              break;
677→            case "emote":
678→              handle.sendEmote(message);
679→              break;
680→            case "whisper":
681→              handle.sendWhisper(mode.target, message);
682→              break;
683→            case "channel":
684→              handle.sendChannel(mode.channel, message);
685→              break;
686→          }
687→        },
688→        invite(name) {
689→          sendPacket(
690→            conn,
691→            GameOpcode.CMSG_GROUP_INVITE,
692→            buildGroupInvite(name),
