714→            conn,
715→            GameOpcode.CMSG_LEAVE_CHANNEL,
716→            buildLeaveChannel(name),
717→          );
718→        },
719→        setLeader(name) {
720→          const member = conn.partyMembers.get(name);
721→          if (!member) {
722→            conn.onMessage?.({
723→              type: ChatType.SYSTEM,
724→              sender: "",
725→              message: `"${name}" is not in your party.`,
726→            });
727→            return;
728→          }
729→          sendPacket(
