 21→  | { type: "accept" }
 22→  | { type: "decline" }
 23→  | { type: "quit" }
 24→  | { type: "tuicraft"; subcommand: string; value: string }
 25→  | { type: "friends" }
 26→  | { type: "add-friend"; target: string }
 27→  | { type: "remove-friend"; target: string }
 28→  | { type: "roll"; min: number; max: number }
 29→  | { type: "ignored" }
 30→  | { type: "add-ignore"; target: string }
 31→  | { type: "remove-ignore"; target: string }
 32→  | { type: "guild-roster" }
 33→  | { type: "guild-invite"; target: string }
 34→  | { type: "guild-kick"; target: string }
 35→  | { type: "guild-leave" }
 36→  | { type: "guild-promote"; target: string }
 37→  | { type: "guild-demote"; target: string }
 38→  | { type: "guild-leader"; target: string }
 39→  | { type: "guild-motd"; message: string }
 40→  | { type: "guild-accept" }
 41→  | { type: "guild-decline" }
 42→  | { type: "unimplemented"; feature: string };
 43→
 44→export function parseCommand(input: string): Command {
 45→  if (!input.startsWith("/")) return { type: "chat", message: input };
 46→
 47→  const spaceIdx = input.indexOf(" ");
 48→  const cmd = spaceIdx === -1 ? input : input.slice(0, spaceIdx);
 49→  const rest = spaceIdx === -1 ? "" : input.slice(spaceIdx + 1);
 50→
 51→  switch (cmd) {
 52→    case "/s":
 53→    case "/say":
 54→      return { type: "say", message: rest };
 55→    case "/y":
 56→    case "/yell":
 57→      return { type: "yell", message: rest };
 58→    case "/g":
 59→    case "/guild":
 60→      return { type: "guild", message: rest };
 61→    case "/p":
 62→    case "/party":
 63→      return { type: "party", message: rest };
 64→    case "/raid":
 65→      return { type: "raid", message: rest };
 66→    case "/w":
 67→    case "/whisper": {
 68→      const targetEnd = rest.indexOf(" ");
 69→      if (targetEnd === -1)
 70→        return { type: "whisper", target: rest, message: "" };
 71→      return {
 72→        type: "whisper",
 73→        target: rest.slice(0, targetEnd),
 74→        message: rest.slice(targetEnd + 1),
 75→      };
 76→    }
 77→    case "/r":
 78→      return { type: "reply", message: rest };
 79→    case "/who":
 80→      return rest ? { type: "who", target: rest } : { type: "who" };
 81→    case "/invite":
 82→      return rest
 83→        ? { type: "invite", target: rest }
 84→        : { type: "say", message: input };
 85→    case "/kick":
 86→      return rest
 87→        ? { type: "kick", target: rest }
 88→        : { type: "say", message: input };
 89→    case "/leave":
 90→      if (rest) return { type: "leave-channel", channel: rest.split(" ")[0]! };
 91→      return { type: "leave" };
 92→    case "/leader":
 93→      return rest
 94→        ? { type: "leader", target: rest }
 95→        : { type: "say", message: input };
 96→    case "/accept":
 97→      return { type: "accept" };
 98→    case "/decline":
 99→      return { type: "decline" };
100→    case "/quit":
101→      return { type: "quit" };
102→    case "/tuicraft": {
103→      const parts = rest.split(" ");
104→      return {
105→        type: "tuicraft",
106→        subcommand: parts[0] ?? "",
107→        value: parts[1] ?? "",
108→      };
109→    }
110→    case "/friends":
111→      return { type: "friends" };
112→    case "/f":
113→      return { type: "friends" };
114→    case "/friend": {
115→      const parts = rest.split(" ");
116→      const sub = parts[0] ?? "";
117→      const target = parts.slice(1).join(" ");
118→      if (sub === "add" && target) return { type: "add-friend", target };
119→      if (sub === "remove" && target) return { type: "remove-friend", target };
120→      return { type: "friends" };
121→    }
122→    case "/ignore":
123→      return rest ? { type: "add-ignore", target: rest } : { type: "ignored" };
124→    case "/unignore":
125→      return rest
126→        ? { type: "remove-ignore", target: rest }
127→        : { type: "say", message: input };
128→    case "/ignorelist":
129→      return { type: "ignored" };
130→    case "/join": {
131→      if (!rest) return { type: "say", message: input };
132→      const [channel, password] = rest.split(" ") as [string, string?];
133→      return { type: "join-channel", channel, password };
134→    }
135→    case "/groster":
136→      return { type: "guild-roster" };
137→    case "/ginvite":
138→      return rest
139→        ? { type: "guild-invite", target: rest }
140→        : { type: "say", message: input };
141→    case "/gkick":
142→      return rest
143→        ? { type: "guild-kick", target: rest }
144→        : { type: "say", message: input };
145→    case "/gleave":
146→      return { type: "guild-leave" };
147→    case "/gpromote":
148→      return rest
149→        ? { type: "guild-promote", target: rest }
150→        : { type: "say", message: input };
151→    case "/gdemote":
152→      return rest
153→        ? { type: "guild-demote", target: rest }
154→        : { type: "say", message: input };
155→    case "/gleader":
156→      return rest
157→        ? { type: "guild-leader", target: rest }
158→        : { type: "say", message: input };
159→    case "/gmotd":
160→      return { type: "guild-motd", message: rest };
161→    case "/gaccept":
162→      return { type: "guild-accept" };
163→    case "/gdecline":
164→      return { type: "guild-decline" };
165→    case "/mail":
166→      return { type: "unimplemented", feature: "Mail reading" };
167→    case "/roll": {
168→      const parts = rest.split(" ").filter(Boolean);
169→      if (parts.length >= 2)
170→        return {
171→          type: "roll",
172→          min: parseInt(parts[0]!, 10),
173→          max: parseInt(parts[1]!, 10),
174→        };
175→      if (parts.length === 1)
176→        return { type: "roll", min: 1, max: parseInt(parts[0]!, 10) };
177→      return { type: "roll", min: 1, max: 100 };
178→    }
179→    case "/dnd":
180→      return { type: "dnd", message: rest };
181→    case "/afk":
182→      return { type: "afk", message: rest };
183→    case "/e":
184→    case "/emote":
185→      return { type: "emote", message: rest };
186→  }
187→
188→  const channelMatch = cmd.match(/^\/(\d+)$/);
189→  return channelMatch
190→    ? { type: "channel", target: channelMatch[1]!, message: rest }
191→    : { type: "say", message: input };
192→}
