 43→    (msg.origin === "server" || msg.origin === "notification")
 44→  ) {
 45→    return `[server] ${message}`;
 46→  }
 47→  if (msg.type === ChatType.SYSTEM && msg.origin === "mail") {
 48→    return `[mail] ${message}`;
