463→  const header = roster.guildName
464→    ? `[guild] ${roster.guildName} — ${online.length}/${roster.members.length} online`
465→    : `[guild] ${online.length}/${roster.members.length} online`;
466→  const lines: string[] = [header];
467→  if (roster.motd) lines.push(`  MOTD: ${roster.motd}`);
468→  if (roster.guildInfo) lines.push(`  Info: ${roster.guildInfo}`);
469→  for (const m of online) {
