  1→import { createInterface } from "node:readline";
  2→import { ChatType } from "wow/protocol/opcodes";
  3→import type { WorldHandle } from "wow/client";
  4→import { parseCommand, type Command } from "ui/commands";
  5→import {
  6→  formatMessage,
  7→  formatError,
  8→  formatWhoResults,
  9→  formatPrompt,
 10→  formatGroupEvent,
 11→  formatEntityEvent,
 12→  formatFriendList,
 13→  formatIgnoreList,
 14→  formatGuildRoster,
 15→} from "ui/format";
 16→
 17→export type TuiState = {
 18→  handle: WorldHandle;
 19→  write: (s: string) => void;
 20→  lastWhisperFrom: string | undefined;
 21→  showEntityEvents: boolean;
 22→};
 23→
 24→export async function executeCommand(
 25→  state: TuiState,
 26→  cmd: Command,
 27→): Promise<boolean> {
 28→  switch (cmd.type) {
 29→    case "chat":
 30→      state.handle.sendInCurrentMode(cmd.message);
 31→      break;
 32→    case "say":
 33→      state.handle.sendSay(cmd.message);
 34→      break;
 35→    case "yell":
 36→      state.handle.sendYell(cmd.message);
 37→      break;
 38→    case "guild":
 39→      state.handle.sendGuild(cmd.message);
 40→      break;
 41→    case "party":
 42→      state.handle.sendParty(cmd.message);
 43→      break;
 44→    case "raid":
 45→      state.handle.sendRaid(cmd.message);
 46→      break;
 47→    case "emote":
 48→      state.handle.sendEmote(cmd.message);
 49→      break;
 50→    case "dnd":
 51→      state.handle.sendDnd(cmd.message);
 52→      break;
 53→    case "afk":
 54→      state.handle.sendAfk(cmd.message);
 55→      break;
 56→    case "whisper":
 57→      state.handle.sendWhisper(cmd.target, cmd.message);
 58→      state.lastWhisperFrom = cmd.target;
 59→      break;
 60→    case "reply":
 61→      if (!state.lastWhisperFrom) {
 62→        state.write(formatError("No one has whispered you yet.") + "\n");
 63→      } else {
 64→        state.handle.sendWhisper(state.lastWhisperFrom, cmd.message);
 65→      }
 66→      break;
 67→    case "channel": {
 68→      const channel = /^\d+$/.test(cmd.target)
 69→        ? state.handle.getChannel(parseInt(cmd.target, 10))
 70→        : cmd.target;
 71→      if (!channel) {
 72→        state.write(formatError(`Not in channel ${cmd.target}.`) + "\n");
 73→      } else {
 74→        state.handle.sendChannel(channel, cmd.message);
 75→      }
 76→      break;
 77→    }
 78→    case "who": {
 79→      const results = await state.handle.who(
 80→        cmd.target ? { name: cmd.target } : {},
 81→      );
 82→      state.write(formatWhoResults(results) + "\n");
 83→      break;
 84→    }
 85→    case "invite":
 86→      state.handle.invite(cmd.target);
 87→      break;
 88→    case "kick":
 89→      state.handle.uninvite(cmd.target);
 90→      break;
 91→    case "leave":
 92→      state.handle.leaveGroup();
 93→      break;
 94→    case "join-channel":
 95→      state.handle.joinChannel(cmd.channel, cmd.password);
 96→      break;
 97→    case "leave-channel":
 98→      state.handle.leaveChannel(cmd.channel);
 99→      break;
100→    case "leader":
101→      state.handle.setLeader(cmd.target);
102→      break;
103→    case "accept":
104→      state.handle.acceptInvite();
105→      break;
106→    case "decline":
107→      state.handle.declineInvite();
108→      break;
109→    case "quit":
110→      return true;
111→    case "tuicraft":
112→      if (cmd.subcommand === "entities") {
113→        if (cmd.value === "on") {
114→          state.showEntityEvents = true;
115→          state.write("[system] Entity events enabled\n");
116→        } else if (cmd.value === "off") {
117→          state.showEntityEvents = false;
118→          state.write("[system] Entity events disabled\n");
119→        } else {
120→          state.write("[system] Usage: /tuicraft entities on|off\n");
121→        }
122→      } else {
123→        state.write(`[system] Unknown tuicraft command: ${cmd.subcommand}\n`);
124→      }
125→      break;
126→    case "friends": {
127→      const friends = state.handle.getFriends();
128→      state.write(formatFriendList(friends) + "\n");
129→      break;
130→    }
131→    case "add-friend":
132→      state.handle.addFriend(cmd.target);
133→      break;
134→    case "remove-friend":
135→      state.handle.removeFriend(cmd.target);
136→      break;
137→    case "ignored": {
138→      const ignored = state.handle.getIgnored();
139→      state.write(formatIgnoreList(ignored) + "\n");
140→      break;
141→    }
142→    case "add-ignore":
143→      state.handle.addIgnore(cmd.target);
144→      break;
145→    case "remove-ignore":
146→      state.handle.removeIgnore(cmd.target);
147→      break;
148→    case "guild-roster": {
149→      const roster = await state.handle.requestGuildRoster();
150→      if (roster) {
151→        state.write(formatGuildRoster(roster) + "\n");
152→      } else {
153→        state.write("[guild] No guild roster available\n");
154→      }
155→      break;
156→    }
157→    case "roll":
158→      state.handle.sendRoll(cmd.min, cmd.max);
159→      break;
160→    case "guild-invite":
161→      state.handle.guildInvite(cmd.target);
