 98→export function parseIpcCommand(line: string): IpcCommand | undefined {
 99→  if (line.startsWith("/")) {
100→    const parsed = parseCommand(line);
101→    switch (parsed.type) {
102→      case "say":
103→      case "yell":
104→      case "guild":
105→      case "party":
106→      case "emote":
107→      case "dnd":
108→      case "afk":
109→        return parsed;
110→      case "whisper":
111→        return parsed;
112→      case "who":
113→        return parsed.target
114→          ? { type: "who", filter: parsed.target }
115→          : { type: "who" };
116→      case "invite":
117→      case "kick":
118→      case "leave":
119→      case "leader":
120→      case "accept":
121→      case "decline":
122→        return parsed;
123→      case "join-channel":
124→        return {
125→          type: "join_channel",
126→          channel: parsed.channel,
127→          password: parsed.password,
128→        };
129→      case "leave-channel":
130→        return { type: "leave_channel", channel: parsed.channel };
131→      case "friends":
132→        return { type: "friends" };
133→      case "add-friend":
134→        return { type: "add_friend", target: parsed.target };
135→      case "remove-friend":
136→        return { type: "del_friend", target: parsed.target };
137→      case "ignored":
138→        return { type: "ignored" };
139→      case "add-ignore":
140→        return { type: "add_ignore", target: parsed.target };
141→      case "remove-ignore":
142→        return { type: "del_ignore", target: parsed.target };
143→      case "roll":
144→        return parsed;
145→      case "guild-roster":
146→        return { type: "guild_roster" };
147→      case "guild-invite":
148→        return { type: "guild_invite", target: parsed.target };
149→      case "guild-kick":
150→        return { type: "guild_kick", target: parsed.target };
151→      case "guild-leave":
152→        return { type: "guild_leave" };
153→      case "guild-promote":
154→        return { type: "guild_promote", target: parsed.target };
155→      case "guild-demote":
156→        return { type: "guild_demote", target: parsed.target };
157→      case "guild-leader":
158→        return { type: "guild_leader", target: parsed.target };
159→      case "guild-motd":
160→        return { type: "guild_motd", message: parsed.message };
161→      case "guild-accept":
162→        return { type: "guild_accept" };
163→      case "guild-decline":
164→        return { type: "guild_decline" };
165→      case "unimplemented":
166→        return parsed;
167→      default:
168→        return { type: "say", message: line };
169→    }
170→  }
171→
172→  const spaceIdx = line.indexOf(" ");
173→  const verb = spaceIdx === -1 ? line : line.slice(0, spaceIdx);
174→  const rest = spaceIdx === -1 ? "" : line.slice(spaceIdx + 1);
175→
176→  switch (verb) {
177→    case "SAY":
178→    case "YELL":
179→    case "GUILD":
180→    case "PARTY":
181→    case "EMOTE":
182→    case "DND":
183→    case "AFK":
184→      return {
185→        type: verb.toLowerCase() as
186→          | "say"
187→          | "yell"
188→          | "guild"
189→          | "party"
190→          | "emote"
191→          | "dnd"
192→          | "afk",
193→        message: rest,
194→      };
195→    case "WHISPER": {
196→      const targetEnd = rest.indexOf(" ");
197→      if (targetEnd === -1)
198→        return { type: "whisper", target: rest, message: "" };
199→      return {
200→        type: "whisper",
201→        target: rest.slice(0, targetEnd),
202→        message: rest.slice(targetEnd + 1),
203→      };
204→    }
205→    case "READ":
206→      return { type: "read" };
207→    case "READ_JSON":
208→      return { type: "read_json" };
209→    case "READ_WAIT": {
210→      const ms = parseInt(rest, 10);
211→      if (!Number.isFinite(ms) || ms < 0) return undefined;
212→      return { type: "read_wait", ms: Math.min(ms, 60_000) };
213→    }
214→    case "READ_WAIT_JSON": {
215→      const ms = parseInt(rest, 10);
216→      if (!Number.isFinite(ms) || ms < 0) return undefined;
217→      return { type: "read_wait_json", ms: Math.min(ms, 60_000) };
218→    }
219→    case "STOP":
220→      return { type: "stop" };
221→    case "STATUS":
222→      return { type: "status" };
223→    case "WHO":
224→      return rest ? { type: "who", filter: rest } : { type: "who" };
225→    case "WHO_JSON":
226→      return rest ? { type: "who_json", filter: rest } : { type: "who_json" };
227→    case "INVITE":
228→      return rest ? { type: "invite", target: rest } : undefined;
229→    case "KICK":
230→      return rest ? { type: "kick", target: rest } : undefined;
231→    case "LEAVE":
232→      if (rest) {
233→        const channel = rest.split(" ")[0]!;
234→        return { type: "leave_channel", channel };
235→      }
236→      return { type: "leave" };
237→    case "LEADER":
238→      return rest ? { type: "leader", target: rest } : undefined;
239→    case "ACCEPT":
240→      return { type: "accept" };
241→    case "DECLINE":
242→      return { type: "decline" };
243→    case "NEARBY":
244→      return { type: "nearby" };
245→    case "NEARBY_JSON":
246→      return { type: "nearby_json" };
247→    case "FRIENDS":
248→      return { type: "friends" };
249→    case "FRIENDS_JSON":
250→      return { type: "friends_json" };
251→    case "ADD_FRIEND":
252→      return rest ? { type: "add_friend", target: rest } : undefined;
253→    case "DEL_FRIEND":
254→      return rest ? { type: "del_friend", target: rest } : undefined;
255→    case "IGNORED":
256→      return { type: "ignored" };
257→    case "IGNORED_JSON":
258→      return { type: "ignored_json" };
259→    case "ADD_IGNORE":
260→      return rest ? { type: "add_ignore", target: rest } : undefined;
261→    case "DEL_IGNORE":
262→      return rest ? { type: "del_ignore", target: rest } : undefined;
263→    case "JOIN": {
264→      if (!rest) return undefined;
265→      const [channel, password] = rest.split(" ") as [string, string?];
266→      return { type: "join_channel", channel, password };
267→    }
268→    case "GUILD_ROSTER":
269→      return { type: "guild_roster" };
270→    case "GUILD_ROSTER_JSON":
271→      return { type: "guild_roster_json" };
272→    case "GINVITE":
273→      return rest ? { type: "guild_invite", target: rest } : undefined;
274→    case "GKICK":
275→      return rest ? { type: "guild_kick", target: rest } : undefined;
276→    case "GLEAVE":
277→      return { type: "guild_leave" };
278→    case "GPROMOTE":
279→      return rest ? { type: "guild_promote", target: rest } : undefined;
280→    case "GDEMOTE":
281→      return rest ? { type: "guild_demote", target: rest } : undefined;
282→    case "GLEADER":
283→      return rest ? { type: "guild_leader", target: rest } : undefined;
284→    case "GMOTD":
285→      return { type: "guild_motd", message: rest };
286→    case "GACCEPT":
287→      return { type: "guild_accept" };
288→    case "GDECLINE":
289→      return { type: "guild_decline" };
290→    case "MAIL":
291→      return { type: "unimplemented", feature: "Mail reading" };
292→    case "ROLL": {
293→      const parts = rest.split(" ").filter(Boolean);
294→      if (parts.length >= 2)
295→        return {
296→          type: "roll",
297→          min: parseInt(parts[0]!, 10),
298→          max: parseInt(parts[1]!, 10),
299→        };
300→      if (parts.length === 1)
301→        return { type: "roll", min: 1, max: parseInt(parts[0]!, 10) };
302→      return { type: "roll", min: 1, max: 100 };
303→    }
304→    default:
305→      return line ? { type: "chat", message: line } : undefined;
306→  }
307→}
308→
309→export function writeLines(socket: IpcSocket, lines: string[]): void {
310→  for (const line of lines) socket.write(line + "\n");
311→  socket.write("\n");
312→}
313→
314→function drainText(events: RingBuffer<EventEntry>): string[] {
315→  return events.drain().flatMap((e) => (e.text !== undefined ? [e.text] : []));
316→}
317→
318→function drainJson(events: RingBuffer<EventEntry>): string[] {
319→  return events.drain().map((e) => e.json);
320→}
321→
322→function sliceText(events: RingBuffer<EventEntry>, from: number): string[] {
323→  return events
324→    .slice(from)
325→    .flatMap((e) => (e.text !== undefined ? [e.text] : []));
326→}
327→
328→function sliceJson(events: RingBuffer<EventEntry>, from: number): string[] {
329→  return events.slice(from).map((e) => e.json);
330→}
