649→function formatGroupEventObj(event: GroupEvent): Record<string, unknown> {
650→  switch (event.type) {
651→    case "invite_received":
652→      return { type: "GROUP_INVITE", from: event.from };
653→    case "command_result":
654→      return {
655→        type: "GROUP_COMMAND_RESULT",
656→        operation: event.operation,
657→        target: event.target,
658→        result: event.result,
659→      };
660→    case "leader_changed":
