749→function formatGuildEvent(event: GuildEvent): string {
750→  switch (event.type) {
751→    case "guild-roster":
752→      return `[guild] Roster updated: ${event.roster.members.length} members`;
753→    case "promotion":
754→      return `[guild] ${event.officer} promoted ${event.member} to ${event.rank}`;
755→    case "demotion":
756→      return `[guild] ${event.officer} demoted ${event.member} to ${event.rank}`;
757→    case "motd":
758→      return `[guild] MOTD: ${event.text}`;
759→    case "joined":
760→      return `[guild] ${event.name} has joined the guild`;
761→    case "left":
762→      return `[guild] ${event.name} has left the guild`;
763→    case "removed":
764→      return `[guild] ${event.officer} removed ${event.member} from the guild`;
765→    case "leader_is":
766→      return `[guild] ${event.name} is the guild leader`;
767→    case "leader_changed":
768→      return `[guild] ${event.oldLeader} has made ${event.newLeader} the new guild leader`;
769→    case "disbanded":
770→      return "[guild] Guild has been disbanded";
771→    case "signed_on":
772→      return `[guild] ${event.name} has come online`;
773→    case "signed_off":
774→      return `[guild] ${event.name} has gone offline`;
775→    case "command_result":
776→      return formatGuildCommandError(event.command, event.name, event.result)!;
777→    case "guild_invite":
778→      return `[guild] ${event.inviter} has invited you to join ${event.guildName}. Use /gaccept or /gdecline`;
779→  }
