863→    case "duel_complete":
864→      return event.completed ? undefined : "[duel] Duel interrupted";
865→    case "duel_winner":
866→      return event.reason === "won"
867→        ? `[duel] ${event.winner} has defeated ${event.loser} in a duel`
868→        : `[duel] ${event.loser} has fled from ${event.winner} in a duel`;
869→    case "duel_out_of_bounds":
870→      return "[duel] Out of bounds \u2014 return to the duel area";
871→    case "duel_in_bounds":
872→      return "[duel] Back in bounds";
873→  }
