  type IgnoreEvent,
} from "wow/ignore-store";
import { GuildStore, type GuildRoster, type GuildEvent } from "wow/guild-store";
import {
  buildAddFriend,
  buildDelFriend,
  buildAddIgnore,
  buildDelIgnore,
} from "wow/protocol/social";
import {
  buildGuildQuery,
  buildGuildInvite,
  buildGuildRemove,
  buildGuildPromote,
  buildGuildDemote,
  buildGuildLeader,
  buildGuildMotd,
} from "wow/protocol/guild";
import { buildDuelAccepted, buildDuelCancelled } from "wow/protocol/duel";
import {
  buildGetMailList,
  buildSendMail,
  buildMailDelete,
  buildMailMarkAsRead,
  type MailEntry,
} from "wow/protocol/mail";
import {
  sendPacket,
  handleTimeSync,
  handleChatMessage,
  handleGmChatMessage,
  handleNameQueryResponse,
  handleMotd,
  handlePlayerNotFound,
  handleChatRestricted,
  handleChatWrongFaction,
  handleChannelNotify,
  handleServerBroadcast,
  handleNotification,
