  | { type: "duel_in_bounds" };

export type { WhoResult };
export type { Entity, EntityEvent };
export type { FriendEntry, FriendEvent };
export type { IgnoreEntry, IgnoreEvent };
export type { GuildRoster, GuildEvent };
export type { MailEntry };

export type ChatMode =
  | { type: "say" }
  | { type: "yell" }
  | { type: "guild" }
