    guildName: roster.guildName,
    motd: roster.motd,
    guildInfo: roster.guildInfo,
    rankNames: roster.rankNames,
    count: roster.members.length,
    online: roster.members.filter((m) => m.status !== GuildMemberStatus.OFFLINE)
