  return JSON.stringify({
    type: "MAIL_READ",
    messageId: entry.messageId,
    sender,
    subject: entry.subject,
    body: entry.body,
    money: entry.money,
    itemCount: entry.itemCount,
    expirationDays: entry.expirationDays,
    read: !!(entry.flags & MailCheckMask.READ),
  });
}

